Event Start
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
&MaxStepsToShow = 8
&WizardStepsAux = &WizardSteps.Clone() &StepNumber = 1 &StepRealNumber = 1 &PreviousSelected = false &FirstIsDummy = False &SecondIsDummy = False &PenultimateIsDummy = False &LastIsDummy = False If &WizardStepsAux.Count > &MaxStepsToShow &MaxStepsToShow -= 1 //the first or last will occupy aprox. 1 step &SelectedStepIndex = 1 For &WizardStep in &WizardStepsAux If &WizardStep.Code = &SelectedStep Exit EndIf &SelectedStepIndex += 1 EndFor If &SelectedStepIndex > &WizardStepsAux.Count &SelectedStepIndex = 1 EndIf &StartIndex = 1 If &SelectedStepIndex + 1 > (&MaxStepsToShow) / 2 &StartIndex = &SelectedStepIndex + 1 - (&MaxStepsToShow) / 2 If &StartIndex + &MaxStepsToShow > &WizardStepsAux.Count + 1 &StartIndex = &WizardStepsAux.Count + 1 - &MaxStepsToShow EndIf EndIf &StepRealNumber = &StartIndex If &StartIndex > 1 &FirstIsDummy = True &MaxStepsToShow += 1 If &StartIndex > 2 &SecondIsDummy = True &MaxStepsToShow += 1 &WizardStepsAux.Item(2).Title = !'...' Do while &StartIndex > 3 &WizardStepsAux.Remove(3) &StartIndex -= 1 Enddo EndIf EndIf
If &WizardStepsAux.Count > &MaxStepsToShow &LastIsDummy = True If &WizardStepsAux.Count > &MaxStepsToShow + 1 &PenultimateIsDummy = True &WizardStepsAux.Item(&WizardStepsAux.Count - 1).Title = !'...' Do while &WizardStepsAux.Count > &MaxStepsToShow + 2 &WizardStepsAux.Remove(&WizardStepsAux.Count - 2) Enddo EndIf EndIf EndIf
EndEvent
Event GridWizardSteps.Load
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//this code should be inside the For Each used to load the grid
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
&TableContainerStepClass = StyleClass:TableContainerStep
StepNumber.Caption = &StepRealNumber.ToFormattedString() If &WizardStepsAux.CurrentItem.Code = &SelectedStep WizardStepsAux__Title.Class = StyleClass:AttributeStepSelected StepImg.FromImage(StepUnSelectedSelected) StepImg.Class = StyleClass:StepImage &TableContainerStepClass = StyleClass:TableContainerStepSelected StepNumber.Class = StyleClass:StepNumberSelected TblStep.Class = StyleClass:TableStepSelected &PreviousSelected = true Else StepImg.FromImage(StepSelectedUnSelected) if &PreviousSelected StepImg.Class = StyleClass:StepImage else StepImg.Class = StyleClass:StepImageUnSelected endif StepNumber.Class = StyleClass:StepNumber TblStep.Class = StyleClass:TableStep WizardStepsAux__Title.Class = StyleClass:AttributeStep &PreviousSelected = false EndIf if &StepNumber = 1 StepImg.Visible = false &TableContainerStepClass = &TableContainerStepClass + " " + StyleClass:TableContainerStepFirst else if &StepNumber = &WizardStepsAux.Count &TableContainerStepClass = &TableContainerStepClass + " " + StyleClass:TableContainerStepLast endif StepImg.Visible = true endif TblContainerStep.Class = &TableContainerStepClass
TblStep.Visible = True StepNumber.Visible = True WizardStepsAux__Title.Visible = True Do Case Case &StepNumber = 1 AND &FirstIsDummy StepNumber.Caption = &StepNumber.ToString().Trim() WizardStepsAux__Title.Visible = False Case &StepNumber = &WizardStepsAux.Count AND &LastIsDummy StepNumber.Caption = &WizardSteps.Count.ToString().Trim() WizardStepsAux__Title.Visible = False Case (&StepNumber = 2 AND &SecondIsDummy) OR (&StepNumber = &WizardStepsAux.Count - 1 AND &PenultimateIsDummy) StepNumber.Visible = False TblStep.Visible = False Otherwise &StepRealNumber += 1 EndCase
&StepNumber += 1
EndEvent
